#!/usr/bin/env bash

set -euo pipefail

echo "====================================================="
echo "      Playwright UI Automation Execution"
echo "====================================================="

echo "Environment : ${ENV:-qa}"
echo "Browser     : ${BROWSER:-chromium}"
echo "Suite       : ${SUITE:-all}"
echo "Shard       : ${SHARD:-none}"
echo "====================================================="

# Build Playwright command
COMMAND=("npx" "playwright" "test")

#########################################################
# Browser
#########################################################

if [[ -n "${BROWSER:-}" ]]; then
    COMMAND+=("--project=${BROWSER}")
fi

#########################################################
# Suite
#########################################################

if [[ "${SUITE:-all}" != "all" ]]; then
    COMMAND+=("--grep" "@${SUITE}")
fi

#########################################################
# Shard
#########################################################

if [[ -n "${SHARD:-}" ]]; then
    COMMAND+=("--shard=${SHARD}")
fi

#########################################################
# Display Command
#########################################################

echo ""
echo "Executing Command:"
printf '%q ' "${COMMAND[@]}"
echo ""
echo ""

#########################################################
# Execute
#########################################################

"${COMMAND[@]}"

#########################################################
# Completed
#########################################################

echo ""
echo "====================================================="
echo "UI Automation Execution Completed Successfully"
echo "====================================================="
